    12→namespace Monolog\Formatter;
    13→
    14→use Stringable;
    15→use Throwable;
    16→use Monolog\LogRecord;
    17→
    18→/**
    19→ * Encodes whatever record data is passed to it as json
    20→ *
    21→ * This can be useful to log to databases or remote APIs
    22→ *
    23→ * @author Jordi Boggiano <j.boggiano@seld.be>
    24→ */
    25→class JsonFormatter extends NormalizerFormatter
    26→{
    27→    public const BATCH_MODE_JSON = 1;
    28→    public const BATCH_MODE_NEWLINES = 2;
    29→
    30→    /** @var self::BATCH_MODE_* */
    31→    protected int $batchMode;
    32→
    33→    protected bool $appendNewline;
    34→
    35→    protected bool $ignoreEmptyContextAndExtra;
    36→
    37→    protected bool $includeStacktraces = false;
    38→
    39→    /**
    40→     * @param self::BATCH_MODE_* $batchMode
    41→     */
    42→    public function __construct(int $batchMode = self::BATCH_MODE_JSON, bool $appendNewline = true, bool $ignoreEmptyContextAndExtra = false, bool $includeStacktraces = false)
    43→    {
    44→        $this->batchMode = $batchMode;
    45→        $this->appendNewline = $appendNewline;
    46→        $this->ignoreEmptyContextAndExtra = $ignoreEmptyContextAndExtra;
    47→        $this->includeStacktraces = $includeStacktraces;
    48→
    49→        parent::__construct();
    50→    }
    51→
    52→    /**
    53→     * The batch mode option configures the formatting style for
    54→     * multiple records. By default, multiple records will be
    55→     * formatted as a JSON-encoded array. However, for
    56→     * compatibility with some API endpoints, alternative styles
    57→     * are available.
    58→     */
    59→    public function getBatchMode(): int
    60→    {
    61→        return $this->batchMode;
    62→    }
    63→
    64→    /**
    65→     * True if newlines are appended to every formatted record
    66→     */
    67→    public function isAppendingNewlines(): bool
    68→    {
    69→        return $this->appendNewline;
    70→    }
    71→
    72→    /**
    73→     * @inheritDoc
    74→     */
    75→    public function format(LogRecord $record): string
    76→    {
    77→        $normalized = $this->normalizeRecord($record);
    78→
    79→        return $this->toJson($normalized, true) . ($this->appendNewline ? "\n" : '');
    80→    }
    81→
    82→    /**
    83→     * @inheritDoc
    84→     */
    85→    public function formatBatch(array $records): string
    86→    {
    87→        return match ($this->batchMode) {
    88→            static::BATCH_MODE_NEWLINES => $this->formatBatchNewlines($records),
    89→            default => $this->formatBatchJson($records),
    90→        };
    91→    }
    92→
    93→    /**
    94→     * @return $this
    95→     */
    96→    public function includeStacktraces(bool $include = true): self
    97→    {
    98→        $this->includeStacktraces = $include;
    99→
   100→        return $this;
   101→    }
   102→
   103→    /**
   104→     * @return array<array<mixed>|bool|float|int|\stdClass|string|null>
   105→     */
   106→    protected function normalizeRecord(LogRecord $record): array
   107→    {
   108→        $normalized = parent::normalizeRecord($record);
   109→
   110→        if (isset($normalized['context']) && $normalized['context'] === []) {
   111→            if ($this->ignoreEmptyContextAndExtra) {
   112→                unset($normalized['context']);
   113→            } else {
   114→                $normalized['context'] = new \stdClass;
   115→            }
   116→        }
   117→        if (isset($normalized['extra']) && $normalized['extra'] === []) {
   118→            if ($this->ignoreEmptyContextAndExtra) {
   119→                unset($normalized['extra']);
   120→            } else {
   121→                $normalized['extra'] = new \stdClass;
   122→            }
   123→        }
   124→
   125→        return $normalized;
   126→    }
   127→
   128→    /**
   129→     * Return a JSON-encoded array of records.
   130→     *
   131→     * @phpstan-param LogRecord[] $records
   132→     */
   133→    protected function formatBatchJson(array $records): string
   134→    {
   135→        $formatted = array_map(fn (LogRecord $record) => $this->normalizeRecord($record), $records);
   136→
   137→        return $this->toJson($formatted, true);
   138→    }
   139→
   140→    /**
   141→     * Use new lines to separate records instead of a
   142→     * JSON-encoded array.
   143→     *
   144→     * @phpstan-param LogRecord[] $records
   145→     */
   146→    protected function formatBatchNewlines(array $records): string
   147→    {
   148→        $oldNewline = $this->appendNewline;
   149→        $this->appendNewline = false;
   150→        $formatted = array_map(fn (LogRecord $record) => $this->format($record), $records);
   151→        $this->appendNewline = $oldNewline;
   152→
   153→        return implode("\n", $formatted);
   154→    }
   155→
   156→    /**
   157→     * Normalizes given $data.
   158→     *
   159→     * @return null|scalar|array<mixed[]|scalar|null|object>|object
   160→     */
   161→    protected function normalize(mixed $data, int $depth = 0): mixed
   162→    {
   163→        if ($depth > $this->maxNormalizeDepth) {
   164→            return 'Over '.$this->maxNormalizeDepth.' levels deep, aborting normalization';
   165→        }
   166→
   167→        if (\is_array($data)) {
   168→            $normalized = [];
   169→
   170→            $count = 1;
   171→            foreach ($data as $key => $value) {
   172→                if ($count++ > $this->maxNormalizeItemCount) {
   173→                    $normalized['...'] = 'Over '.$this->maxNormalizeItemCount.' items ('.\count($data).' total), aborting normalization';
   174→                    break;
   175→                }
   176→
   177→                $normalized[$key] = $this->normalize($value, $depth + 1);
   178→            }
   179→
   180→            return $normalized;
   181→        }
   182→
   183→        if (\is_object($data)) {
   184→            if ($data instanceof \DateTimeInterface) {
   185→                return $this->formatDate($data);
   186→            }
   187→
   188→            if ($data instanceof Throwable) {
   189→                return $this->normalizeException($data, $depth);
   190→            }
   191→
   192→            // if the object has specific json serializability we want to make sure we skip the __toString treatment below
   193→            if ($data instanceof \JsonSerializable) {
   194→                return $data;
   195→            }
   196→
   197→            if ($data instanceof Stringable) {
   198→                return $data->__toString();
   199→            }
   200→
   201→            if (\get_class($data) === '__PHP_Incomplete_Class') {
   202→                return new \ArrayObject($data);
   203→            }
   204→
   205→            return $data;
   206→        }
   207→
   208→        if (\is_resource($data)) {
   209→            return parent::normalize($data);
   210→        }
   211→
   212→        return $data;
   213→    }
   214→
   215→    /**
   216→     * Normalizes given exception with or without its own stack trace based on
   217→     * `includeStacktraces` property.
   218→     *
   219→     * @return array<array-key, string|int|array<string|int|array<string>>>
   220→     */
   221→    protected function normalizeException(Throwable $e, int $depth = 0): array
   222→    {
   223→        $data = parent::normalizeException($e, $depth);
   224→        if (!$this->includeStacktraces) {
   225→            unset($data['trace']);
   226→        }
   227→
   228→        return $data;
   229→    }
   230→}
